dtsPropsFor.Button:
/** Visual style. Defaults to "primary". */
variant?: "primary" | "secondary" | "ghost" | "outline";
/** Control height. Defaults to "md". */
size?: "sm" | "md" | "lg";
/** Show a leading spinner and disable the button while true. */
loading?: boolean;
children?: React.ReactNode;
className?: string;
disabled?: boolean;
type?: "button" | "submit" | "reset";
onClick?: React.MouseEventHandler<HTMLButtonElement>;

dtsPropsFor.IconButton:
/** Accessible label; rendered as aria-label and title. Required. */
label: string;
/** Control size. Defaults to "md". */
size?: "sm" | "md" | "lg";
/** Persistent pressed/active styling. */
active?: boolean;
/** Icon element (e.g. a lucide-react icon). */
children?: React.ReactNode;
className?: string;
disabled?: boolean;
onClick?: React.MouseEventHandler<HTMLButtonElement>;

dtsPropsFor.Spinner:
className?: string;
/** Pixel size of the spinner. Defaults to 16. */
size?: number;

dtsPropsFor.Tooltip:
/** Tooltip text shown on hover/focus. */
label: string;
/** The element the tooltip is attached to. */
children: React.ReactNode;
/** Which side of the trigger the tooltip appears on. Defaults to "top". */
side?: "top" | "bottom";
className?: string;

dtsPropsFor.Modal:
/** Whether the modal is visible. */
open: boolean;
/** Called on Escape, overlay click, or the close button. */
onClose: () => void;
/** Optional header title. */
title?: React.ReactNode;
children: React.ReactNode;
className?: string;

dtsPropsFor.Dropdown:
/** The element that toggles the menu. */
trigger: React.ReactNode;
/** Render-prop for the menu body; receives a `close` callback to dismiss the menu. */
children: (close: () => void) => React.ReactNode;
/** Horizontal alignment of the menu relative to the trigger. Defaults to "start". */
align?: "start" | "end";
/** Vertical placement relative to the trigger. Defaults to "bottom". */
side?: "top" | "bottom";
className?: string;
menuClassName?: string;
/** When true, the trigger does not open the menu. */
disabled?: boolean;

dtsPropsFor.DropdownItem:
/** Click handler for the menu item. */
onClick?: () => void;
children: React.ReactNode;
/** Destructive (red) styling. */
danger?: boolean;
/** Highlighted/selected styling. */
active?: boolean;
className?: string;
